import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as cdk from 'aws-cdk-lib';

export class LambdaSecurityStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // High-risk function with strict concurrency limit
    const dataProcessingFunction = new lambda.Function(this, 'DataProcessor', {
      runtime: lambda.Runtime.NODEJS_20_X,
      handler: 'index.handler',
      code: lambda.Code.fromAsset('lambda'),
      timeout: cdk.Duration.seconds(30), // Reduced from default 3 minutes
      memorySize: 512,
      // CRITICAL: Reserve concurrency to prevent account-wide exhaustion
      reservedConcurrentExecutions: 10, // Max 10 concurrent executions
      environment: {
        MAX_PROCESSING_TIME_MS: '25000' // Internal timeout guard
      }
    });

    // Public-facing function with even stricter limits
    const publicApiFunction = new lambda.Function(this, 'PublicAPI', {
      runtime: lambda.Runtime.PYTHON_3_12,
      handler: 'app.lambda_handler',
      code: lambda.Code.fromAsset('api'),
      timeout: cdk.Duration.seconds(10), // Short timeout for API responses
      memorySize: 256,
      reservedConcurrentExecutions: 5, // Very restrictive for public endpoints
      layers: [
        // Include AWS Lambda Powertools for structured logging
        lambda.LayerVersion.fromLayerVersionArn(
          this,
          'PowertoolsLayer',
          'arn:aws:lambda:us-east-1:017000801446:layer:AWSLambdaPowertoolsPythonV2:59'
        )
      ]
    });

    // Add CloudWatch alarms for throttling
    const throttleAlarm = publicApiFunction.metricThrottles().createAlarm(this, 'ThrottleAlarm', {
      threshold: 5,
      evaluationPeriods: 1,
      datapointsToAlarm: 1,
      treatMissingData: cdk.aws_cloudwatch.TreatMissingData.NOT_BREACHING
    });
  }
}

import time
import signal
import json
from typing import Dict, Any
from contextlib import contextmanager

# Lambda Powertools for structured logging
from aws_lambda_powertools import Logger, Tracer
from aws_lambda_powertools.utilities.typing import LambdaContext

logger = Logger()
tracer = Tracer()

# Timeout exception for circuit breaker
class TimeoutError(Exception):
    pass

def timeout_handler(signum, frame):
    raise TimeoutError("Function execution exceeded internal timeout")

@contextmanager
def timeout_guard(seconds: int):
    """Internal timeout guard - triggers before Lambda timeout"""
    signal.signal(signal.SIGALRM, timeout_handler)
    signal.alarm(seconds)
    try:
        yield
    finally:
        signal.alarm(0)

@logger.inject_lambda_context(log_event=True)
@tracer.capture_lambda_handler
def lambda_handler(event: Dict[str, Any], context: LambdaContext) -> Dict[str, Any]:
    """
    Lambda handler with internal timeout protection
    Lambda timeout: 30 seconds (configured in infrastructure)
    Internal timeout: 25 seconds (leaves 5s buffer for cleanup)
    """

    # Calculate internal timeout (90% of Lambda timeout)
    lambda_timeout_ms = context.get_remaining_time_in_millis()
    internal_timeout_sec = int((lambda_timeout_ms / 1000) * 0.9)

    logger.info({
        "message": "Function invocation started",
        "request_id": context.request_id,
        "timeout_config": {
            "lambda_timeout_ms": lambda_timeout_ms,
            "internal_timeout_sec": internal_timeout_sec
        }
    })

    try:
        with timeout_guard(internal_timeout_sec):
            # Perform processing
            result = process_request(event, context)

            logger.info({
                "message": "Processing completed successfully",
                "execution_time_ms": lambda_timeout_ms - context.get_remaining_time_in_millis()
            })

            return {
                "statusCode": 200,
                "body": json.dumps(result)
            }

    except TimeoutError:
        logger.error({
            "message": "Internal timeout exceeded - graceful shutdown",
            "timeout_sec": internal_timeout_sec
        })

        # Return partial results or retry instruction
        return {
            "statusCode": 503,
            "body": json.dumps({
                "error": "Request timeout - please retry",
                "retry_after": 60
            })
        }

    except Exception as e:
        logger.exception("Unexpected error during processing")
        return {
            "statusCode": 500,
            "body": json.dumps({"error": "Internal server error"})
        }

def process_request(event: Dict[str, Any], context: LambdaContext) -> Dict[str, Any]:
    """Business logic with periodic timeout checks"""
    start_time = time.time()
    results = []

    for item in event.get('items', []):
        # Check remaining time before each iteration
        if context.get_remaining_time_in_millis() < 5000:  # 5 second buffer
            logger.warning({
                "message": "Approaching timeout - stopping processing",
                "items_processed": len(results),
                "items_remaining": len(event['items']) - len(results)
            })
            break

        # Process item (simulate work)
        processed = process_item(item)
        results.append(processed)

    return {
        "processed_count": len(results),
        "execution_time": time.time() - start_time
    }

def process_item(item: Any) -> Any:
    """Process individual item - add your business logic here"""
    # Simulate processing
    time.sleep(0.1)
    return {"id": item.get('id'), "status": "processed"}

import * as cdk from 'aws-cdk-lib';
import * as sns from 'aws-cdk-lib/aws-sns';
import * as subscriptions from 'aws-cdk-lib/aws-sns-subscriptions';
import * as cloudwatch from 'aws-cdk-lib/aws-cloudwatch';
import * as actions from 'aws-cdk-lib/aws-cloudwatch-actions';
import * as events from 'aws-cdk-lib/aws-events';
import * as targets from 'aws-cdk-lib/aws-events-targets';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as iam from 'aws-cdk-lib/aws-iam';

export class LambdaSecurityMonitoringStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // SNS topic for security alerts
    const securityAlertTopic = new sns.Topic(this, 'LambdaSecurityAlerts', {
      displayName: 'Lambda Security Alerts',
      topicName: 'lambda-security-alerts'
    });

    // Email subscription for alerts
    securityAlertTopic.addSubscription(
      new subscriptions.EmailSubscription('security-team@example.com')
    );

    // Slack/PagerDuty webhook (optional)
    securityAlertTopic.addSubscription(
      new subscriptions.UrlSubscription('https://hooks.slack.com/services/YOUR/WEBHOOK/URL')
    );

    // CloudWatch Alarm: Account-level concurrent execution threshold
    const accountConcurrencyAlarm = new cloudwatch.Alarm(this, 'AccountConcurrencyAlarm', {
      alarmName: 'lambda-account-concurrency-high',
      alarmDescription: 'Alert when account concurrency exceeds 80% of limit',
      metric: new cloudwatch.Metric({
        namespace: 'AWS/Lambda',
        metricName: 'ConcurrentExecutions',
        statistic: 'Maximum',
        period: cdk.Duration.minutes(1)
      }),
      threshold: 800, // 80% of default 1,000 limit
      evaluationPeriods: 2,
      datapointsToAlarm: 2,
      treatMissingData: cloudwatch.TreatMissingData.NOT_BREACHING,
      comparisonOperator: cloudwatch.ComparisonOperator.GREATER_THAN_THRESHOLD
    });

    accountConcurrencyAlarm.addAlarmAction(new actions.SnsAction(securityAlertTopic));

    // CloudWatch Alarm: Throttle spike detection
    const throttleAlarm = new cloudwatch.Alarm(this, 'ThrottleAlarm', {
      alarmName: 'lambda-throttle-spike',
      alarmDescription: 'Alert on Lambda throttling events',
      metric: new cloudwatch.Metric({
        namespace: 'AWS/Lambda',
        metricName: 'Throttles',
        statistic: 'Sum',
        period: cdk.Duration.minutes(5)
      }),
      threshold: 10,
      evaluationPeriods: 1,
      treatMissingData: cloudwatch.TreatMissingData.NOT_BREACHING,
      comparisonOperator: cloudwatch.ComparisonOperator.GREATER_THAN_THRESHOLD
    });

    throttleAlarm.addAlarmAction(new actions.SnsAction(securityAlertTopic));

    // CloudWatch Alarm: Duration anomaly (functions running close to timeout)
    const durationAlarm = new cloudwatch.Alarm(this, 'DurationAlarm', {
      alarmName: 'lambda-duration-anomaly',
      alarmDescription: 'Alert when function duration exceeds 90% of timeout',
      metric: new cloudwatch.Metric({
        namespace: 'AWS/Lambda',
        metricName: 'Duration',
        statistic: 'Maximum',
        period: cdk.Duration.minutes(5)
      }),
      threshold: 27000, // 27 seconds (90% of 30s timeout)
      evaluationPeriods: 2,
      datapointsToAlarm: 2,
      treatMissingData: cloudwatch.TreatMissingData.NOT_BREACHING,
      comparisonOperator: cloudwatch.ComparisonOperator.GREATER_THAN_THRESHOLD
    });

    durationAlarm.addAlarmAction(new actions.SnsAction(securityAlertTopic));

    // Lambda function to process GuardDuty findings
    const guardDutyProcessor = new lambda.Function(this, 'GuardDutyProcessor', {
      runtime: lambda.Runtime.PYTHON_3_12,
      handler: 'guardduty_handler.lambda_handler',
      code: lambda.Code.fromInline(`
import json
import boto3
import os

sns = boto3.client('sns')
lambda_client = boto3.client('lambda')

def lambda_handler(event, context):
    finding = event['detail']
    finding_type = finding.get('type', '')
    severity = finding.get('severity', 0)

    # Check for crypto mining findings
    crypto_findings = [
        'CryptoCurrency:Runtime/BitcoinTool.B!DNS',
        'CryptoCurrency:Runtime/BitcoinTool.B',
        'Impact:Runtime/CryptoMinerExecuted'
    ]

    if any(f in finding_type for f in crypto_findings):
        # Extract affected Lambda function
        resource = finding.get('resource', {})
        function_name = resource.get('lambdaDetails', {}).get('functionName')

        message = f"""
🚨 CRITICAL: Crypto Mining Detected in Lambda Function

Function: {function_name}
Finding Type: {finding_type}
Severity: {severity}
Account: {finding.get('accountId')}
Region: {finding.get('region')}
Time: {finding.get('time')}

Description: {finding.get('description')}

IMDIATE ACTIONS REQUIRED:
1. Update function's reserved concurrency to 0 (disable invocations)
2. Review function code and dependencies
3. Rotate IAM credentials
4. Check CloudTrail for unauthorized deployments
5. Review AWS Cost Explorer for anomalies
        """

        # Send SNS alert
        sns.publish(
            TopicArn=os.environ['ALERT_TOPIC_ARN'],
            Subject=f'🚨 CRITICAL: Lambda Crypto Mining - {function_name}',
            Message=message
        )

        # OPTIONAL: Auto-disable function by setting concurrency to 0
        # Uncomment if auto-remediation is desired
        # try:
        #     lambda_client.put_function_concurrency(
        #         FunctionName=function_name,
        #         ReservedConcurrentExecutions=0
        #     )
        #     print(f'Auto-disabled function: {function_name}')
        # except Exception as e:
        #     print(f'Failed to disable function: {e}')

    return {'statusCode': 200}
      `),
      environment: {
        ALERT_TOPIC_ARN: securityAlertTopic.topicArn
      },
      timeout: cdk.Duration.seconds(30)
    });

    // Grant permissions
    securityAlertTopic.grantPublish(guardDutyProcessor);
    guardDutyProcessor.addToRolePolicy(new iam.PolicyStatement({
      actions: ['lambda:PutFunctionConcurrency', 'lambda:GetFunction'],
      resources: ['*']
    }));

    // EventBridge rule for GuardDuty findings
    const guardDutyRule = new events.Rule(this, 'GuardDutyLambdaFindings', {
      ruleName: 'guardduty-lambda-crypto-mining',
      description: 'Trigger on GuardDuty Lambda crypto mining findings',
      eventPattern: {
        source: ['aws.guardduty'],
        detailType: ['GuardDuty Finding'],
        detail: {
          type: [{
            prefix: 'CryptoCurrency:Runtime'
          }, {
            prefix: 'Impact:Runtime/CryptoMinerExecuted'
          }],
          resource: {
            resourceType: ['Lambda']
          }
        }
      }
    });

    guardDutyRule.addTarget(new targets.LambdaFunction(guardDutyProcessor));

    // Cost Anomaly Detection (configured via AWS Console/CLI)
    // Note: Cost Anomaly Detection doesn't have CDK L2 constructs yet
    // Must be configured manually or via AWS CLI
    new cdk.CfnOutput(this, 'CostAnomalyInstructions', {
      value: 'Configure Cost Anomaly Detection in AWS Cost Management console',
      description: 'Enable ML-based cost anomaly detection for Lambda service'
    });
  }
}

